<template>
  <div class="chess-board-wrap" :class="boardThemeClass">
    <div ref="boardEl" class="cg-wrap" />
    <div v-if="promotionPending" class="promotion-overlay" @click.self="cancelPromotion">
      <div class="promotion-dialog" :class="promotionDialogClass">
        <button
          v-for="role in promotionRoles"
          :key="role"
          class="promotion-piece"
          @click="selectPromotion(role)"
        >
          <img :src="getPromotionIcon(role, promotionColor)" :alt="role" class="promotion-icon" />
        </button>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, watch, onMounted, onUnmounted, nextTick } from 'vue'
import type { Config } from 'chessground/config'
import type { Key, Role, Color } from 'chessground/types'
import { useChessground, type ChessgroundCallbacks } from '~/composables/useChessground'

export interface BoardConfig {
  orientation?: 'white' | 'black'
  viewOnly?: boolean
  coordinates?: boolean
  premovable?: { enabled?: boolean }
  movableColor?: 'white' | 'black' | 'both' | undefined
  movableEnabled?: boolean
}

type PieceTheme = 'cburnett' | 'tatiana' | 'maestro' | 'pirouetti'
type BoardTheme = 'brown' | 'blue' | 'green' | 'purple' | 'ic'

const props = withDefaults(defineProps<{
  boardConfig?: BoardConfig
  playerColor?: 'white' | 'black' | 'both'
  reactiveConfig?: boolean
  pieceTheme?: PieceTheme
  boardTheme?: BoardTheme
}>(), {
  boardConfig: () => ({}),
  playerColor: 'both',
  reactiveConfig: false,
  pieceTheme: 'cburnett',
  boardTheme: 'brown',
})

const emit = defineEmits<{
  'board-created': [api: ReturnType<typeof useChessground>]
  'move': [move: { from: string; to: string; promotion?: string; san: string; captured?: string }]
  'check': []
  'checkmate': []
  'stalemate': []
  'draw': []
}>()

const boardEl = ref<HTMLElement | null>(null)
const promotionPending = ref(false)
let pendingPromotion: { orig: Key; dest: Key } | null = null

const callbacks: ChessgroundCallbacks = {
  onMove: (move) => emit('move', move),
  onCheck: () => emit('check'),
  onCheckmate: () => emit('checkmate'),
  onStalemate: () => emit('stalemate'),
  onDraw: () => emit('draw'),
  onPromotionNeeded: (orig, dest) => {
    pendingPromotion = { orig, dest }
    promotionPending.value = true
  },
}

const cg = useChessground({ callbacks })

const promotionColor = computed<Color>(() => {
  const turn = cg.chess.value.turn()
  return turn === 'w' ? 'white' : 'black'
})

const promotionDialogClass = computed(() => {
  const orientation = cg.cg.value?.state?.orientation ?? props.boardConfig.orientation ?? 'white'
  return orientation === 'black' ? 'promotion-top' : 'promotion-bottom'
})

const promotionRoles: Role[] = ['queen', 'rook', 'bishop', 'knight']

const boardThemeClass = computed(() => `board-theme-${props.boardTheme}`)

const promotionIconMap: Record<string, Record<string, string>> = {
  cburnett: {
    'queen-white': 'data:image/svg+xml;base64,',
    'rook-white': 'data:image/svg+xml;base64,',
    'bishop-white': 'data:image/svg+xml;base64,',
    'knight-white': 'data:image/svg+xml;base64,',
    'queen-black': 'data:image/svg+xml;base64,',
    'rook-black': 'data:image/svg+xml;base64,',
    'bishop-black': 'data:image/svg+xml;base64,',
    'knight-black': 'data:image/svg+xml;base64,',
  },
}

const getPromotionIcon = (role: Role, color: Color): string => {
  const key = `${role}-${color}`
  const themeIcons = promotionIconMap[props.pieceTheme] ?? promotionIconMap.cburnett!
  return themeIcons[key] ?? ''
}

const toCgConfig = (config: BoardConfig): Partial<Config> => {
  const effectiveColor = config.movableColor !== undefined ? config.movableColor : props.playerColor
  const movableEnabled = config.movableEnabled !== false
  const isInteractive = effectiveColor !== undefined
  const result: Partial<Config> = {
    orientation: config.orientation,
    viewOnly: !isInteractive,
    coordinates: config.coordinates,
  }
  if (isInteractive) {
    result.movable = {
      color: effectiveColor === 'both' ? 'both' : (effectiveColor as Color),
      enabled: movableEnabled,
    }
  }
  if (config.premovable?.enabled !== undefined) {
    result.premovable = { enabled: config.premovable.enabled }
  }
  return result
}

const loadPieceTheme = async (theme: PieceTheme) => {
  const id = 'chess-piece-theme'
  let link = document.getElementById(id) as HTMLLinkElement | null
  if (link) link.remove()
  link = document.createElement('link')
  link.id = id
  link.rel = 'stylesheet'
  link.href = `/css/pieces/${theme}.css`
  document.head.appendChild(link)
  await new Promise<void>((resolve) => {
    link!.onload = () => resolve()
    link!.onerror = () => resolve()
  })
}

const loadBoardTheme = async (theme: BoardTheme) => {
  const id = 'chess-board-theme'
  let link = document.getElementById(id) as HTMLLinkElement | null
  if (link) link.remove()
  link = document.createElement('link')
  link.id = id
  link.rel = 'stylesheet'
  link.href = `/css/boards/${theme}.css`
  document.head.appendChild(link)
  await new Promise<void>((resolve) => {
    link!.onload = () => resolve()
    link!.onerror = () => resolve()
  })
}

onMounted(async () => {
  await loadPieceTheme(props.pieceTheme)
  await loadBoardTheme(props.boardTheme)

  await nextTick()
  if (boardEl.value) {
    cg.init(boardEl.value, toCgConfig(props.boardConfig))
    emit('board-created', cg)
  }
})

onUnmounted(() => {
  cg.destroy()
})

watch(() => props.boardConfig, (config) => {
  if (props.reactiveConfig && cg.cg.value) {
    cg.setConfig(toCgConfig(config))
  }
}, { deep: true })

watch(() => props.pieceTheme, (theme) => {
  loadPieceTheme(theme).then(() => cg.cg.value?.redrawAll())
})

watch(() => props.boardTheme, (theme) => {
  loadBoardTheme(theme).then(() => cg.cg.value?.redrawAll())
})

const selectPromotion = (role: Role) => {
  if (pendingPromotion) {
    cg.promote(pendingPromotion.orig, pendingPromotion.dest, role)
  }
  promotionPending.value = false
  pendingPromotion = null
}

const cancelPromotion = () => {
  promotionPending.value = false
  pendingPromotion = null
  cg.cancelPromotion()
}
defineExpose({
  ...cg,
})
</script>

<style scoped>
.chess-board-wrap {
  position: relative;
  width: 100%;
  height: 100%;
  overflow: hidden;
}

@media (min-width: 1024px) {
  .chess-board-wrap {
    border-radius: var(--ui-radius, 0.5rem);
  }
}

.chess-board-wrap .cg-wrap {
  width: 100%;
  height: 100%;
}

.promotion-overlay {
  position: absolute;
  inset: 0;
  z-index: 100;
  background: rgba(0, 0, 0, 0.4);
  display: flex;
  align-items: flex-start;
  justify-content: center;
}

.promotion-dialog {
  display: flex;
  flex-direction: column;
  background: var(--ui-bg, #fff);
  border-radius: 0.5rem;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.3);
  overflow: hidden;
  margin-top: 0;
}

.promotion-dialog.promotion-bottom {
  margin-top: 0;
}

.promotion-dialog.promotion-top {
  position: absolute;
  bottom: 0;
}

.promotion-piece {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 64px;
  height: 64px;
  border: none;
  background: transparent;
  cursor: pointer;
  transition: background 0.15s;
}

.promotion-piece:hover {
  background: rgba(0, 0, 0, 0.1);
}

.promotion-icon {
  width: 48px;
  height: 48px;
}
</style>
